	case runtimesignals.StatusAvailable, runtimesignals.StatusDegraded:
		return StatusAvailable
	case runtimesignals.StatusExhausted:
		return StatusRateLimited
	case runtimesignals.StatusUnknown:
		return StatusUnknown
	default:
